bx_import('BxDolTwigModule');class RwProfileTabModule extends BxDolTwigModule {	var $_ParamSearch;	    function RwProfileTabModule($aModule) {        parent::BxDolModule($aModule);    }			function actionHome($avalue1 = '', $avalue2 = '', $avalue3 = '') {				echo 'Hello Good User';			}	function serviceProfileTabCustom ($iProfileId) {		        $this->_oTemplate->addCss(array('main.css'));				echo $this->_serviceProfileTabCustom ($iProfileId);	}	function _serviceProfileTabCustom($iProfileId) {		$aProfileTabs = $this->_oDb->getProfileTabs();				$MaxTabsNumber = getParam ('profile_tabs_number');		$counter = 1;		$showMoreTab = false;				foreach($aProfileTabs as $aEach) {			if($counter > $MaxTabsNumber) {				$showMoreTab = true;				$moretabCon .= '<li><span class="prof-tabs-more"><a href="javascript:void(0);" onclick="changeTab('.$aEach['tabs_id'].');">'._t($aEach['tabs_caption']).'</a></span></li>';			}			else{				$sTabsCode .=  '<li><span class="prof-tabs-default"><a href="javascript:void(0);" onclick="changeTab('.$aEach['tabs_id'].');">'._t($aEach['tabs_caption']).'</a></span></li>';			}			if($counter == 1){				$contentDivs .= '<div id="ptab-content-'.$aEach['tabs_id'].'"></div>';				$defaultId = (int) $aEach['tabs_id'];			}			else{				$contentDivs .= '<div id="ptab-content-'.$aEach['tabs_id'].'" style="display:none;"></div>';			}			$Jquery .= $this->GetTabsData ($aEach['tabs_id']);			$counter++;		}		if($showMoreTab){			$sTabsCode .= '<li id="see-more-ptabs"><span class="prof-tabs-default"><a href="javascript:void(0);">'._t('rw_ptabs_moretabs').'</span></a>						   <ul id="prof-more-tabs">'.$moretabCon.'</ul>';		}		$adata = array(			'tabs' => $sTabsCode,			'default' => $contentDivs,			'default_id' => $defaultId,			'jquery' => $Jquery,		);		return $this->_oTemplate->parseHtmlByName('profile_tabs.html', $adata);	}	function GetTabsData ($id) {		$aProfileTabs = $this->_oDb->getProfileTabsTwo($id);		foreach($aProfileTabs as $aEach) {			$Jquery .= '$("#page_block_'.$aEach['ID'].'").appendTo("#ptab-content-'.$id.'");';			}		return $Jquery;	}	function actionAdministration ($sUrl = '', $sParam1 = '') {        if (!$GLOBALS['logged']['admin']) {             $this->_oTemplate->displayAccessDenied ();            return;        }				 /* remove profile Tabs */        if ($_POST['action_add_delete'] && is_array($_POST['tabs'])){		            foreach ($_POST['tabs'] as $tabs) {                $this->_oDb->RemoveProfileTabItems($tabs);			}		}		 /* save profile Tabs */        if (isset($_POST['action_add_save']) && is_array($_POST['tabs'])){			            foreach ($_POST['tabs'] as $tabkey => $tabs) {            	$order = $_POST['order'][$tabkey];            	$type = $_POST['typeentry'.$tabs];				$tabsId = $tabs;				                $this->_oDb-> UpdateProfileTabBlocks($order, $tabsId, $type);			}			header('location: /modules/?r=ptabs/administration/manage');			exit;		}				 /* Add profile blocks to Tabs */        if (isset($_POST['addnewtab'])){			$blockId = (int) $_POST['addnewtab'];			$tabType = strip_tags($_POST['type']);            $this->_oDb->AddProfileTabBlock($blockId, $tabType);					}		/* Add new profile tabs */        if (isset($_POST['addnewptab'])){			$Tabname = strip_tags($_POST['addnewptab']);            $this->_oDb->AddProfileTab($Tabname);					}		/* Update profile tabs */        if (isset($_POST['editprofiletab'])){			$Tabname = strip_tags($_POST['editprofiletabCaption']);			$TabId = (int) $_POST['editptab'];            $this->_oDb->UpdateProfileTab($Tabname, $TabId);					}		/* Delete profile tabs */        if (isset($_POST['deleteprofiletab'])){			$TabId = (int) $_POST['editptab'];            $this->_oDb->DeleteProfileTab($TabId);					}		/* Sort profile tabs */        if (isset($_POST['sort_tabs'])){			$list = parse_str($_POST['sort_tabs'], $output);			$track = array();			$track = $output['tab'];						foreach ($track as $key => $value) {				$oInsertSortApps = $this->_oDb->insertSortTabs($key, $value);			}			echo $_POST['sort_tabs'];			return;		}		$aMenu = array(            'manage' => array(                'title' => 'Manage ProfileTab',                 'href' => BX_DOL_URL_ROOT . $this->_oConfig->getBaseUri() . 'administration/manage',                '_func' => array ('name' => 'actionAdministrationManage', 'params' => array($sParam1)),            ),			'settings' => array(                'title' => 'Settings',                'href' => BX_DOL_URL_ROOT . $this->_oConfig->getBaseUri() . 'administration/settings',                '_func' => array ('name' => 'actionAdministrationSettings', 'params' => array()),            )        );				if (empty($aMenu[$sUrl]))            $sUrl = 'manage';		        $aMenu[$sUrl]['active'] = 1;        $sContent = call_user_func_array(array($this, $aMenu[$sUrl]['_func']['name']), $aMenu[$sUrl]['_func']['params']);        $this->_oTemplate->pageStart();        echo $this->_oTemplate->adminBlock ($sContent, 'Profile Tabs Customization', $aMenu);				$this->_oTemplate->addCssAdmin ('main.css');                $this->_oTemplate->pageCodeAdmin ('Profile Tabs Customization');     }    function getTabItems($id) {    	$aProfileTabs = $this->_oDb->getAllProfiletabsItems($id);    	$typeArray = $this->_oDb->getProfileTabs();    	$tabContent .= '<table>';    	foreach($aProfileTabs as $prolfetab){    		$tabType = '';    		foreach($typeArray as $tabsName) {    			if($id == $tabsName['tabs_id']){    				$tabType .= '<option value="'.$tabsName['tabs_id'].'" selected="selected">'._t($tabsName['tabs_caption']).'</option>';    			}    			else{					$tabType .= '<option value="'.$tabsName['tabs_id'].'">'._t($tabsName['tabs_caption']).'</option>';				}			}			$tabContent .= '<tr class="admin-profile-tabs" style="margin:5px;">							<td><input <input type="checkbox" name="tabs[]" value="'.$prolfetab['profile_tabs_id'].'" /></td>							<td style="width: 250px;"><span style="margin-left: 10px; margin-right: 10px;">'._t($prolfetab['Caption']).'</span></td>													<td><select name="typeentry'.$prolfetab['profile_tabs_id'].'">'.$tabType.'</select></td>							</tr>';		}		$tabContent .= '</table>';		return $tabContent;    }    function actionAdministrationManage() {    	bx_import('BxTemplSearchResult');    	$oSearchResult = new BxTemplSearchResult();				$aButtons = array(            'action_add_save' => 'Save',            'action_add_delete' => 'Delete'        );				$aPageBlocks = $this->_oDb->getAllProfileBlocks();		$aTabType = $this->_oDb->getProfileTabs();		foreach($aPageBlocks as $pageBlocks) {			if(empty($pageBlocks['profile_tabs_id'])){				$pageBlockoption .= '<option value="'.$pageBlocks['ID'].'">'._t($pageBlocks['Caption']).'</option>';			}		}		foreach($aTabType as $tabsName) {				$tabType .= '<option value="'.$tabsName['tabs_id'].'">'._t($tabsName['tabs_caption']).'</option>';				$tabContent .= '<div id="tab_'.$tabsName['tabs_id'].'" style="margin-bottom:10px;border:1px solid gray;background-color: #FAFAFA;"><span style="font-size:15px;color:#fff;background-color:gray;cursor:move;padding:5px;display:block;">								<span class="tabconhandel" style="margin-right:8px;"<i class="sys-icon move"></i></span>								'._t($tabsName['tabs_caption']).'</span>'.$this->getTabItems($tabsName['tabs_id']).'</div>';		}		$sActionsPanel = $oSearchResult->showAdminActionsPanel('adminAddAction', $aButtons, '', false);		$aResult = array(			'actions_panel' => $sActionsPanel,			'pblockoption' => $pageBlockoption,			'content' => $tabContent,			'tab_type_option' => $tabType,		);	        return $this->_oTemplate->parseHtmlByName('manage.html', $aResult);    }    function actionAdministrationSettings() {			 $iId = $this->_oDb->getSettingsCategory(); 	    if(empty($iId)) {             echo MsgBox(_t('_sys_request_page_not_found_cpt'));            /*$this->_oTemplate->pageCodeAdmin (_t('_me_blgg'));*/            return;        }        bx_import('BxDolAdminSettings');         $mixedResult = '';        if(isset($_POST['save']) && isset($_POST['cat'])) { 	        $oSettings = new BxDolAdminSettings($iId);            $mixedResult = $oSettings->saveChanges($_POST);        }        $oSettings = new BxDolAdminSettings($iId);         $sResult = $oSettings->getForm();    	               if($mixedResult !== true && !empty($mixedResult))             $sResult = $mixedResult . $sResult;					$aCode = 'Apps Settings';		return $sResult;	}	}?>